import React, { useState } from 'react';

const App = () => {
  const [messages, setMessages] = useState([]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);

  const handleSendMessage = () => {
    setMessages([...messages, inputValue]);
    setInputValue('');
    setIsTyping(false);
  };

  const handleInputChange = (e) => {
    setInputValue(e.target.value);
    setIsTyping(true);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#F7F7F7] p-4 rounded">
        <div className="flex justify-between items-center mb-4">
          <input
            className="text-black p-2 bg-transparent border border-gray-400 rounded focus:outline-none focus:ring focus:border-blue-500"
            type="text"
            value={inputValue}
            onChange={handleInputChange}
            placeholder="Type a message..."
          />
          <button
            className="p-2 bg-[#C06C88] text-white rounded hover:bg-[#B7D7CD]"
            onClick={handleSendMessage}
          >Send</button>
        </div>
        <ul className="list-none mb-4">
          {messages.map((message, index) => (
            <li key={index} className="mb-2">
              <p className="text-white">{message}</p>
            </li>
          ))}
        </ul>
        {isTyping && <p className="text-white mb-4">Typing...</p>}
      </div>
    </div>
  );
};

export default App;
